sql:
SELECT DISTINCT customer_id 
FROM policies
WHERE policy_deductible > 500;

SELECT policy_id, policy_number, policy_bind_date
FROM policies
WHERE policy_status = 'Active';

SELECT claim_id, incident_date, incident_type, total_claim_amount, claim_description
FROM claims
WHERE total_claim_amount = (SELECT MIN(total_claim_amount) FROM claims);

SELECT event_type, event_description 
FROM claim_history 
WHERE claim_id = 1;

external_knowledge:
Insurance policies: Types of insurance customers have purchased; 
A decade of policies: Customers having more than 10 insurance policies are excluded from the count;
Variety: Refers to different types of insurance policies available;
Credit score: Financial reliability score of a customer;
Folks: Refers to the total number of customers.

- 'most creditworthy' refers to customers with the highest credit score;
- 'top premium policy' refers to those with the highest annual premium among all policies;
- 'biggest claims' refer to claims with the highest total amount, sorted in descending order.

